mapper.sql:
WHERE B.USE_YN = 'Y'

    AND B.CO_ID = #{coId}


    AND (
        B.BIZ_NM LIKE CONCAT('%', #{searchKeyword}, '%')
        OR B.DTL_BIZ_NM LIKE CONCAT('%', #{searchKeyword}, '%')
    )


    AND B.BIZ_PRGRS_STEP_CD = #{searchBizPrgrsStepCd}


    AND B.BIZ_STTS_CD = #{searchBizSttsCd}


    AND B.BIZ_BGNG_YMD >= #{startYmd}


    AND B.BIZ_END_YMD <= #{endYmd}

mapper.select:
SELECT B.BIZ_SN ,B.CO_ID ,B.BIZ_NM ,B.DTL_BIZ_NM ,B.CTRT_YMD ,B.BIZ_BGNG_YMD ,B.BIZ_END_YMD ,B.CTRT_AMT ,B.VAT_INCL_YN ,B.BIZ_PRGRS_STEP_CD ,B.BIZ_STTS_CD ,B.RMRK_CN ,B.USE_YN ,B.RGTR_ID ,DATE_FORMAT(B.REG_DT, '%Y-%m-%d %H:%i:%s') AS REG_DT ,B.MDFR_ID ,DATE_FORMAT(B.MDFCN_DT, '%Y-%m-%d %H:%i:%s') AS MDFCN_DT , ,IFNULL(CST.DIRECT_CST_SUM, 0) AS DIRECT_CST_SUM ,IFNULL(MNPW.LABOR_CST_SUM, 0) AS LABOR_CST_SUM ,IFNULL(CST.DIRECT_CST_SUM, 0) + IFNULL(MNPW.LABOR_CST_SUM, 0) AS TOTAL_CST_SUM ,B.CTRT_AMT - (IFNULL(CST.DIRECT_CST_SUM, 0) + IFNULL(MNPW.LABOR_CST_SUM, 0)) AS PROFIT_AMT ,CASE WHEN B.CTRT_AMT = 0 THEN 0 ELSE ROUND((B.CTRT_AMT - (IFNULL(CST.DIRECT_CST_SUM, 0) + IFNULL(MNPW.LABOR_CST_SUM, 0))) / B.CTRT_AMT * 100, 2) END AS PROFIT_RATE FROM biz_info B LEFT JOIN ( SELECT BIZ_SN, SUM(OCRN_CST) AS DIRECT_CST_SUM FROM biz_cst WHERE USE_YN = 'Y' GROUP BY BIZ_SN ) CST ON B.BIZ_SN = CST.BIZ_SN LEFT JOIN ( SELECT BIZ_SN, SUM(INPUT_MCNT * UNTPRC) AS LABOR_CST_SUM FROM biz_mnpw WHERE USE_YN = 'Y' GROUP BY BIZ_SN ) MNPW ON B.BIZ_SN = MNPW.BIZ_SN
ORDER BY B.BIZ_SN DESC
LIMIT #{firstIndex}, #{recordCountPerPage}

mapper.insert:
INSERT INTO biz_info (
     CO_ID, BIZ_NM, DTL_BIZ_NM, CTRT_YMD, BIZ_BGNG_YMD, BIZ_END_YMD
    ,CTRT_AMT, VAT_INCL_YN, BIZ_PRGRS_STEP_CD, BIZ_STTS_CD
    ,RMRK_CN, USE_YN, RGTR_ID, REG_DT
) VALUES (
     #{coId}, #{bizNm}, #{dtlBizNm}, #{ctrtYmd}, #{bizBgngYmd}, #{bizEndYmd}
    ,IFNULL(#{ctrtAmt}, 0), IFNULL(#{vatInclYn}, 'Y'), IFNULL(#{bizPrgrsStepCd}, 'PRE_WORK'), IFNULL(#{bizSttsCd}, 'READY')
    ,#{rmrkCn}, 'Y', #{rgtrId}, NOW()
)

mapper.update:
UPDATE biz_info
SET
     BIZ_NM = #{bizNm}
    ,DTL_BIZ_NM = #{dtlBizNm}
    ,CTRT_YMD = #{ctrtYmd}
    ,BIZ_BGNG_YMD = #{bizBgngYmd}
    ,BIZ_END_YMD = #{bizEndYmd}
    ,CTRT_AMT = IFNULL(#{ctrtAmt}, 0)
    ,VAT_INCL_YN = IFNULL(#{vatInclYn}, 'Y')
    ,BIZ_PRGRS_STEP_CD = #{bizPrgrsStepCd}
    ,BIZ_STTS_CD = #{bizSttsCd}
    ,RMRK_CN = #{rmrkCn}
    ,MDFR_ID = #{mdfrId}
    ,MDFCN_DT = NOW()
WHERE BIZ_SN = #{bizSn}

mapper.insert:
INSERT INTO cust_info (
     CUST_CO_NM, CUST_SE_CD, BRNO, RPRSV_NM, TELNO, ADDR, DADDR
    ,RMRK_CN, USE_YN, RGTR_ID, REG_DT
) VALUES (
     #{custCoNm}, #{custSeCd}, #{brno}, #{rprsvNm}, #{telno}, #{addr}, #{daddr}
    ,#{rmrkCn}, 'Y', #{rgtrId}, NOW()
)

mapper.update:
UPDATE cust_info
SET
     CUST_CO_NM = #{custCoNm}
    ,CUST_SE_CD = #{custSeCd}
    ,BRNO = #{brno}
    ,RPRSV_NM = #{rprsvNm}
    ,TELNO = #{telno}
    ,ADDR = #{addr}
    ,DADDR = #{daddr}
    ,RMRK_CN = #{rmrkCn}
    ,MDFR_ID = #{mdfrId}
    ,MDFCN_DT = NOW()
WHERE CUST_SN = #{custSn}

UPDATE biz_cust_rel
SET
     CUST_SN = #{custSn}
    ,REL_SE_CD = #{relSeCd}
    ,REL_LVL = IFNULL(#{relLvl}, 0)
    ,SORT_SEQ = IFNULL(#{relSortSeq}, 1)
    ,DIRECT_CTRT_YN = IFNULL(#{directCtrtYn}, 'N')
    ,OUR_CO_YN = IFNULL(#{ourCoYn}, 'N')
    ,RMRK_CN = #{rmrkCn}
    ,MDFR_ID = #{mdfrId}
    ,MDFCN_DT = NOW()
WHERE BIZ_CUST_REL_SN = #{bizCustRelSn}

mapper.insert:
INSERT INTO biz_mnpw (
     BIZ_SN, USER_ID, INPUT_MNPW_NM, INPUT_SE_CD, BIZ_PRGRS_STEP_CD
    ,ROLE_NM, JBPS_NM, INPUT_BGNG_YMD, INPUT_END_YMD, INPUT_MCNT, UNTPRC
    ,RMRK_CN, USE_YN, RGTR_ID, REG_DT
) VALUES (
     #{bizSn}, #{userId}, #{inputMnpwNm}, #{inputSeCd}, #{bizPrgrsStepCd}
    ,#{roleNm}, #{jbpsNm}, #{inputBgngYmd}, #{inputEndYmd}, IFNULL(#{inputMcnt}, 0), IFNULL(#{untprc}, 0)
    ,#{rmrkCn}, 'Y', #{rgtrId}, NOW()
)

mapper.update:
UPDATE biz_mnpw
SET
     USER_ID = #{userId}
    ,INPUT_MNPW_NM = #{inputMnpwNm}
    ,INPUT_SE_CD = #{inputSeCd}
    ,BIZ_PRGRS_STEP_CD = #{bizPrgrsStepCd}
    ,ROLE_NM = #{roleNm}
    ,JBPS_NM = #{jbpsNm}
    ,INPUT_BGNG_YMD = #{inputBgngYmd}
    ,INPUT_END_YMD = #{inputEndYmd}
    ,INPUT_MCNT = IFNULL(#{inputMcnt}, 0)
    ,UNTPRC = IFNULL(#{untprc}, 0)
    ,RMRK_CN = #{rmrkCn}
    ,MDFR_ID = #{mdfrId}
    ,MDFCN_DT = NOW()
WHERE BIZ_MNPW_SN = #{bizMnpwSn}

